import { By } from "selenium-webdriver";
import ojwd, { DriverLike, register } from "../../";
import { OjButtonsetMany } from "./OjButtonsetMany";
export { OjButtonsetMany };

/**
 * Create an instance of [[OjButtonsetMany]].  This function will first wait for
 * the element to appear in the DOM before trying to locate it.
 * @example
 * <code>
 * const el = await ojButtonsetMany(driver, By.id('my-oj-buttonset-many'))
 * </code>
 * @param driver A WebDriver/WebElement instance used to locate the component
 * element.
 * @param by The By locator with which to find the element
 */
export async function ojButtonsetMany(driver: DriverLike, by: By): Promise<OjButtonsetMany> {
  const webEl = await driver.findElement(by);
  // Check that the element is of type OjButtonsetMany
  if (!(webEl instanceof OjButtonsetMany)) {
    const tagName = await webEl.getTagName();
    throw Error(`Locator '${by}' located a <${tagName}>, but expected <oj-buttonset-many>`);
  }
  return webEl;
}

register("oj-buttonset-many", OjButtonsetMany);
